use aiken/math
use cardano/transaction.{OutputReference, Transaction}

pub type ThresholdDatum {
  value: Int,
  max_abs: Int,
}

validator abs_threshold {
  spend(
    datum: Option<ThresholdDatum>,
    _redeemer: Data,
    _ref: OutputReference,
    _self: Transaction,
  ) -> Bool {
    when datum is {
      None -> False
      Some(d) -> math.abs(d.value) <= d.max_abs
    }
  }

  else(_) {
    fail
  }
}

