pub type BoundsDatum {
  a: Int,
  b: Int,
  must_use_min: Bool,
  threshold: Int,
}

validator min_max_check {
  spend(
    datum: Option<BoundsDatum>,
    _redeemer: Data,
    _ref: OutputReference,
    _self: Transaction,
  ) -> Bool {
    when datum is {
      None -> False
      Some(d) ->
        if d.must_use_min {
          math.min(d.a, d.b) >= d.threshold
        } else {
          math.max(d.a, d.b) <= d.threshold
        }
    }
  }

  else(_) {
    fail
  }
}

