use aiken/math/rational
use cardano/transaction.{OutputReference, Transaction}

pub type RatioDatum {
  numerator: Int,
  denominator: Int,
  min_ratio_num: Int,
  min_ratio_den: Int,
}

validator ratio_check {
  spend(
    datum: Option<RatioDatum>,
    _redeemer: Data,
    _ref: OutputReference,
    _self: Transaction,
  ) -> Bool {
    when datum is {
      None -> False
      Some(d) -> {
        let actual_ratio = rational.new(d.numerator, d.denominator)
        let min_ratio = rational.new(d.min_ratio_num, d.min_ratio_den)
        when (actual_ratio, min_ratio) is {
          (Some(actual), Some(min)) ->
            when rational.compare(actual, min) is {
              Less -> False
              Equal -> True
              Greater -> True
            }
          _ -> False
        }
      }
    }
  }
}

