  fee: Int,
  max_fee_bps: Int,
}

validator fee_ratio_validator {
  spend(
    datum: Option<FeeDatum>,
    _redeemer: Data,
    _ref: OutputReference,
    _self: Transaction,
  ) -> Bool {
    when datum is {
      None -> False
      Some(d) -> {
        expect Some(fee_ratio) = rational.new(d.fee, d.amount)
        expect Some(max_ratio) = rational.new(d.max_fee_bps, 10000)
        when rational.compare(fee_ratio, max_ratio) is {
          Less -> True
          Equal -> True
          Greater -> False
        }
      }
    }
  }

  else(_) {
    fail
  }
}

