pub type InterestDatum {
  principal: Int,
  rate_num: Int,
  rate_den: Int,
  min_interest: Int,
}

validator interest_calculator {
  spend(
    datum: Option<InterestDatum>,
    _redeemer: Data,
    _ref: OutputReference,
    _self: Transaction,
  ) -> Bool {
    when datum is {
      None -> False
      Some(d) ->
        when rational.new(d.rate_num, d.rate_den) is {
          None -> False
          Some(rate) -> {
            let principal_rational = rational.from_int(d.principal)
            let interest = rational.mul(principal_rational, rate)
            let computed_interest = rational.floor(interest)
            computed_interest >= d.min_interest
          }
        }
    }
  }
}

use aiken/math/rational
use cardano/transaction.{OutputReference, Transaction}

pub type SplitDatum {
  total: Int,
  share_num: Int,
  share_den: Int,
  recipient_min: Int,
}

fn compute_share(total: Int, share_num: Int, share_den: Int) -> Option<Int> {
  when rational.new(share_num, share_den) is {
    None -> None
    Some(share_ratio) -> {
      let total_rational = rational.from_int(total)
      let product = rational.mul(total_rational, share_ratio)
      Some(rational.floor(product))
    }
  }
}

validator split_validator {
  spend(
    datum: Option<SplitDatum>,
    _redeemer: Data,
    _ref: OutputReference,
    _self: Transaction,
  ) -> Bool {
    when datum is {
      None -> False
      Some(d) -> {
        when compute_share(d.total, d.share_num, d.share_den) is {
          None -> False
          Some(share_amount) -> share_amount >= d.recipient_min
        }
      }
    }
  }
}

