pub type FractionDatum {
  num: Int,
  den: Int,
  expected_num: Int,
  expected_den: Int,
}

validator reduced_fraction {
  spend(
    datum: Option<FractionDatum>,
    _redeemer: Data,
    _ref: OutputReference,
    _self: Transaction,
  ) -> Bool {
    when datum is {
      None -> False
      Some(d) ->
        when rational.new(d.num, d.den) is {
          None -> False
          Some(r) -> {
            let reduced = rational.reduce(r)
            let actual_num = rational.numerator(reduced)
            let actual_den = rational.denominator(reduced)
            actual_num == d.expected_num && actual_den == d.expected_den
          }
        }
    }
  }

  else(_) {
    fail
  }
}

