pub type MathDatum {
  base: Int,
  exp: Int,
  divisor: Int,
  min_result: Int,
}

validator compound_math {
  spend(
    datum: Option<MathDatum>,
    _redeemer: Data,
    _ref: OutputReference,
    _self: Transaction,
  ) -> Bool {
    when datum is {
      None -> False
      Some(d) -> {
        let val = math.pow(d.base, d.exp)
        when rational.new(val, d.divisor) is {
          None -> False
          Some(r) -> {
            let quotient = rational.floor(r)
            quotient >= d.min_result
          }
        }
      }
    }
  }
}

